{
  "summary": "目标为直连式IVI节点，无网关防护，SSH与Telnet服务均暴露，存在弱认证与明文传输风险，推荐采用 direct 攻击路径。",
  "open_ports": [22, 23],
  "services": [
    {
      "port": 22,
      "service": "SSH",
      "banner": "OpenSSH_10.2p1 Debian-5",
      "auth_type": "password",
      "risk": "high"
    },
    {
      "port": 23,
      "service": "Telnet",
      "banner": "no_banner_received",
      "auth_type": "plaintext",
      "risk": "critical"
    }
  ],
  "topology": {
    "has_security_gateway": false,
    "recommended_attack_vector": "direct",
    "node_count": 1,
    "nodes": [
      {
        "ip": "172.16.64.129",
        "name": "Primary Target",
        "is_behind_gateway": false,
        "open_ports": [22, 23],
        "services": ["SSH", "Telnet"]
      }
    ]
  }
}

{
  "strategy_summary": "优先利用高危明文传输的Telnet服务进行凭据获取或会话劫持，同步尝试SSH弱口令爆破与密钥认证探测，避免直接触发防御机制。",
  "steps": [
    {
      "step": 1,
      "title": "Telnet服务交互与凭据嗅探",
      "objective": "验证Telnet服务是否接受匿名登录或返回可识别凭据（如默认账号/密码、调试信息）",
      "success_criteria": "成功建立Telnet连接并获取有效登录提示、banner、或响应中包含用户名/密码线索",
      "depends_on": []
    },
    {
      "step": 2,
      "title": "SSH服务指纹与认证方式深度探测",
      "objective": "确认SSH是否支持弱算法、空口令、或密钥认证，并识别允许的认证方法（password/publickey）",
      "success_criteria": "获取SSH服务器支持的认证方式列表（如'publickey,password'），排除密钥强制策略",
      "depends_on": ["step 1"]
    },
    {
      "step": 3,
      "title": "基于常见IVI默认凭据的轻量级爆破",
      "objective": "使用车载系统高频默认凭据集（如root:root, admin:admin, ivi:ivi）对Telnet和SSH并发尝试登录",
      "success_criteria": "任一服务返回认证成功（如Shell提示符、'Last login'等有效响应）",
      "depends_on": ["step 2"]
    },
    {
      "step": 4,
      "title": "SSH密钥泄露路径探测（若支持publickey）",
      "objective": "检查是否存在已知私钥泄露模式（如/.ssh/id_rsa暴露于Web路径、/etc/ssh/未授权读取）",
      "success_criteria": "发现可读取的私钥文件路径或SSH配置中AllowUsers/AuthorizedKeysFile异常配置",
      "depends_on": ["step 3"]
    },
    {
      "step": 5,
      "title": "会话接管与权限提升验证",
      "objective": "在成功登录后验证是否具备命令执行能力、文件读写权限及提权路径（如sudo无密码、SUID二进制）",
      "success_criteria": "执行'id'、'ls -l /etc/shadow'、'sudo -l'等命令返回预期结果且无访问拒绝",
      "depends_on": ["step 3", "step 4"]
    }
  ],
  "guardrails": [
    "避免重复调用同一工具（如连续多次telnet/ssh连接未加延迟）",
    "避免错误扩散（如爆破失败后不自动切换至高风险exploit模块）",
    "连续3次步骤失败（如全凭据尝试失败+密钥路径未命中）时终止并建议人工介入"
  ]
}

